const toolInput = ($json.tool_input && typeof $json.tool_input === 'object') ? $json.tool_input : {};
const raw = { ...$json, ...toolInput };
const message = String(raw.message || raw.media_caption || '').trim();
const buttonId = String(raw.button_id || '').trim();
const sourceType = String(raw.source_type || (buttonId ? 'button' : 'text')).trim() || 'text';
return [{ json: {
  ...raw,
  chat_id: String(raw.chat_id || ''),
  message,
  button_id: buttonId,
  source_type: sourceType,
  media_id: raw.media_id || '',
  media_mime_type: raw.media_mime_type || '',
  media_filename: raw.media_filename || '',
  media_caption: raw.media_caption || '',
  user_language: String(raw.user_language || 'en'),
} }];

const raw = $('Normalize Input').first().json;
const store = $('Resolve Store Context').first().json || {};
const inventory = $('Load Inventory Snapshot').all().map((item) => item.json || {}).filter((row) => row && row.item_name);
const promos = $('Load Promo Snapshot').all().map((item) => item.json || {}).filter((row) => row && row.promo_code);
const sessions = $('Load Promo Session State').all().map((item) => item.json || {}).filter((row) => row && row.session_id);
const aiText = (() => { try { return $('Claude Promo Extractor').first().json.text || ''; } catch { return ''; } })();
const message = String(raw.message || '').trim();
const buttonId = String(raw.button_id || '').trim();
const sourceType = String(raw.source_type || 'text');
const onboardingStep = Number(store.onboarding_step || 0);
const isComplete = onboardingStep >= 6 && !!store.store_name && !!store.upi_id && !!store.delivery_area && !!store.operating_hours;
const base = { ...raw, ...store };

const TOKEN_ALIASES = {
  pyaaz: 'onion', piaz: 'onion', kanda: 'onion', peyaj: 'onion', vengayam: 'onion', onoin: 'onion',
  aloo: 'potato', alu: 'potato', batata: 'potato',
  tamatar: 'tomato', tamato: 'tomato', tamoto: 'tomato',
  doodh: 'milk', chawal: 'rice', anda: 'egg', ande: 'egg', mutta: 'egg', dim: 'egg',
  maggie: 'maggi', magi: 'maggi',
};
const UNIT_ALIASES = { kg: 'kg', kilo: 'kg', kilogram: 'kg', g: 'g', gm: 'g', gram: 'g', l: 'l', litre: 'l', liter: 'l', ltr: 'l', ml: 'ml' };

function compactUnits(value) {
  return String(value || '')
    .replace(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilogram|g|gm|gram|ml|l|ltr|litre|liter)\b/gi, (_, num, unit) => num + (UNIT_ALIASES[String(unit).toLowerCase()] || String(unit).toLowerCase()))
    .replace(/[\u2013\u2014-]+/g, ' ')
    .replace(/[()_,/]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeToken(token) {
  const rawValue = compactUnits(token).toLowerCase().replace(/[^a-z0-9.]+/g, ' ').trim();
  if (!rawValue) return '';
  const mapped = TOKEN_ALIASES[rawValue] || rawValue;
  if (mapped.endsWith('ies') && mapped.length > 4) return mapped.slice(0, -3) + 'y';
  if (mapped.endsWith('oes') && mapped.length > 4) return mapped.slice(0, -2);
  if (mapped.endsWith('ses') && mapped.length > 4) return mapped.slice(0, -2);
  if (mapped.endsWith('s') && !mapped.endsWith('ss') && mapped.length > 3) return mapped.slice(0, -1);
  return mapped;
}

function isVariant(token) {
  return /^\d+(?:\.\d+)?(?:kg|g|ml|l)?$/i.test(String(token || '').trim());
}

function canonicalizeItemName(value) {
  return compactUnits(value).split(/\s+/).filter(Boolean).map((token) => {
    if (isVariant(token)) return token.toLowerCase();
    return token.charAt(0).toUpperCase() + token.slice(1).toLowerCase();
  }).join(' ').trim();
}

function profile(value) {
  const cleaned = compactUnits(value);
  const tokens = cleaned.split(/\s+/).filter(Boolean).map((token) => normalizeToken(token)).filter(Boolean);
  return {
    cleaned,
    display_name: canonicalizeItemName(value),
    normalized_key: tokens.join(' ').trim(),
    base_tokens: tokens.filter((token) => !isVariant(token)),
    variant_tokens: tokens.filter((token) => isVariant(token)),
  };
}

function score(a, b) {
  if (!a.normalized_key || !b.normalized_key) return 0;
  if (a.normalized_key === b.normalized_key) return 1;
  if (b.normalized_key.startsWith(a.normalized_key) || a.normalized_key.startsWith(b.normalized_key)) return 0.9;
  if (b.normalized_key.includes(a.normalized_key) || a.normalized_key.includes(b.normalized_key)) return 0.82;
  const left = new Set(a.base_tokens);
  const right = new Set(b.base_tokens);
  const common = [...left].filter((token) => right.has(token)).length;
  const union = new Set([...left, ...right]).size || 1;
  let value = common / union;
  if (a.base_tokens.length && common === a.base_tokens.length) value = Math.max(value, 0.76);
  if (a.variant_tokens.length && a.variant_tokens.every((token) => b.variant_tokens.includes(token))) value += 0.2;
  return value;
}

function distinct(rowsToMap) {
  return [...new Set(rowsToMap.map((row) => canonicalizeItemName(row.item_name || '')).filter(Boolean))];
}

function parseAiPayload(text) {
  const rawText = String(text || '').trim();
  if (!rawText) return {};
  const ticks = String.fromCharCode(96) + String.fromCharCode(96) + String.fromCharCode(96);
  const fenced = rawText
    .replace(new RegExp('^' + ticks + 'json', 'i'), '')
    .replace(new RegExp('^' + ticks, 'i'), '')
    .replace(new RegExp(ticks + '$', 'i'), '')
    .trim();
  const start = fenced.indexOf('{');
  const end = fenced.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return {};
  try { return JSON.parse(fenced.slice(start, end + 1)); } catch { return {}; }
}

function parseExpiry(text) {
  const value = String(text || '').trim().toLowerCase();
  if (!value) return '';
  const now = new Date();
  const endOfDay = (date) => {
    const d = new Date(date);
    d.setHours(23, 59, 59, 0);
    return d.toISOString();
  };
  if (value === 'today') return endOfDay(now);
  if (value === 'tomorrow') return endOfDay(new Date(now.getTime() + 24 * 60 * 60 * 1000));
  const daysMatch = value.match(/(\d+)\s+days?/);
  if (daysMatch) return endOfDay(new Date(now.getTime() + Number(daysMatch[1]) * 24 * 60 * 60 * 1000));
  const isoMatch = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (isoMatch) return endOfDay(new Date(Number(isoMatch[1]), Number(isoMatch[2]) - 1, Number(isoMatch[3])));
  const dmyMatch = value.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (dmyMatch) return endOfDay(new Date(Number(dmyMatch[3]), Number(dmyMatch[2]) - 1, Number(dmyMatch[1])));
  return '';
}

function parsePriority(text) {
  const value = String(text || '').trim().toLowerCase();
  if (/high/.test(value)) return { label: 'High', value: 30 };
  if (/low/.test(value)) return { label: 'Low', value: 10 };
  if (/medium|normal|default/.test(value)) return { label: 'Medium', value: 20 };
  return null;
}

function nextPromoCode(baseCode) {
  const used = new Set(promos.map((row) => String(row.promo_code || '').toUpperCase()));
  let code = String(baseCode || '').toUpperCase().replace(/[^A-Z0-9_]+/g, '').slice(0, 24) || 'DEAL';
  let suffix = 2;
  while (used.has(code)) {
    code = (String(baseCode || 'DEAL').toUpperCase().replace(/[^A-Z0-9_]+/g, '').slice(0, 20) || 'DEAL') + '_' + suffix;
    suffix += 1;
  }
  return code;
}

function buildPreviewDraft(draft) {
  const existingMatch = promos.find((promo) =>
    promo.is_active !== false
    && String(promo.promo_scope || '') === String(draft.promo_scope || '')
    && String(promo.discount_type || '') === String(draft.discount_type || '')
    && Number(promo.discount_value || 0) === Number(draft.discount_value || 0)
    && Number(promo.min_cart_value || 0) === Number(draft.min_cart_value || 0)
    && String(promo.target_sku || '') === String(draft.target_sku || '')
  );
  const codeBase = draft.target_label
    ? profile(draft.target_label).normalized_key.toUpperCase().replace(/[^A-Z0-9]+/g, '').slice(0, 8)
    : (draft.promo_scope === 'order' && draft.discount_type === 'flat')
      ? 'FLAT' + Math.round(Number(draft.discount_value || 0))
      : 'SAVE' + Math.round(Number(draft.discount_value || 0));
  return {
    promo_scope: draft.promo_scope,
    discount_type: draft.discount_type,
    discount_value: Number(draft.discount_value || 0),
    min_cart_value: Number(draft.min_cart_value || 0),
    promo_code: nextPromoCode(draft.promo_code || codeBase),
    target_sku: String(draft.target_sku || ''),
    target_label: draft.target_label || '',
    target_category: draft.target_category || '',
    valid_until: draft.valid_until || '',
    priority_value: Number(draft.priority_value || 20),
    priority_label: draft.priority_label || 'Medium',
    description: draft.description || (
      draft.promo_scope === 'product'
        ? (Number(draft.discount_value || 0) + '% off on ' + draft.target_label)
        : draft.discount_type === 'flat'
          ? ('Rs.' + Number(draft.discount_value || 0) + ' off on the order')
          : Number(draft.min_cart_value || 0) > 0
            ? (Number(draft.discount_value || 0) + '% off orders above Rs.' + Number(draft.min_cart_value || 0))
            : (Number(draft.discount_value || 0) + '% off on the order')
    ),
    existing_active_code: existingMatch ? existingMatch.promo_code : '',
  };
}

function resolveItem(label) {
  const query = profile(String(label || '').replace(/^(?:on|for|an|a|the)\s+/i, '').trim());
  const active = inventory.filter((row) => row.is_active !== false).map((row) => ({ ...row, item_name: canonicalizeItemName(row.item_name), _profile: profile(row.item_name) }));
  if (!query.normalized_key) return { status: 'not_found', matches: [], options: [] };
  const exact = active.filter((row) => row._profile.normalized_key === query.normalized_key);
  if (exact.length === 1) return { status: 'selected', row: exact[0], matches: [exact[0].item_name], options: [{ target_sku: String(exact[0].sku || ''), target_label: exact[0].item_name, target_category: exact[0].category || '' }] };
  if (exact.length > 1) return { status: 'ambiguous', matches: distinct(exact), options: exact.slice(0, 3).map((row) => ({ target_sku: String(row.sku || ''), target_label: row.item_name, target_category: row.category || '' })) };
  const exactBase = active.filter((row) => row._profile.base_tokens.join(' ') === query.base_tokens.join(' '));
  if (!query.variant_tokens.length && exactBase.length === 1) return { status: 'selected', row: exactBase[0], matches: [exactBase[0].item_name], options: [{ target_sku: String(exactBase[0].sku || ''), target_label: exactBase[0].item_name, target_category: exactBase[0].category || '' }] };
  if (!query.variant_tokens.length && exactBase.length > 1) return { status: 'ambiguous', matches: distinct(exactBase), options: exactBase.slice(0, 3).map((row) => ({ target_sku: String(row.sku || ''), target_label: row.item_name, target_category: row.category || '' })) };
  const ranked = active.map((row) => ({ row, score: score(query, row._profile) })).filter((row) => row.score >= 0.55).sort((left, right) => right.score - left.score);
  if (!ranked.length) return { status: 'not_found', matches: [], options: [] };
  const topScore = ranked[0].score;
  const topGroup = ranked.filter((row) => row.score >= topScore - 0.08);
  const labels = distinct(topGroup.map((row) => row.row));
  if (labels.length === 1) return { status: 'selected', row: topGroup[0].row, matches: labels, options: [{ target_sku: String(topGroup[0].row.sku || ''), target_label: topGroup[0].row.item_name, target_category: topGroup[0].row.category || '' }] };
  return { status: 'ambiguous', matches: labels, options: topGroup.slice(0, 3).map((row) => ({ target_sku: String(row.row.sku || ''), target_label: row.row.item_name, target_category: row.row.category || '' })) };
}

function loadSession(sessionId) {
  if (!sessionId) return null;
  return sessions.find((row) => String(row.session_id || '') === String(sessionId)) || null;
}

if (!isComplete) return [{ json: { ...base, action: 'needs_onboarding' } }];
if (sourceType === 'document' || sourceType === 'image') return [{ json: { ...base, action: 'media_not_supported' } }];

if (buttonId === 'owner_catalog_discount' || buttonId === 'owner_promo_create_another') return [{ json: { ...base, action: 'start_prompt_session' } }];
if (buttonId === 'owner_promo_show_active') return [{ json: { ...base, action: 'list' } }];
if (buttonId === 'owner_promo_back_catalog') return [{ json: { ...base, action: 'back_catalog' } }];
if (buttonId.startsWith('owner_promo_confirm__')) return [{ json: { ...base, action: 'confirm_session', session_id: buttonId.replace('owner_promo_confirm__', '') } }];
if (buttonId.startsWith('owner_promo_cancel__')) return [{ json: { ...base, action: 'cancel_session', session_id: buttonId.replace('owner_promo_cancel__', '') } }];

const targetButton = buttonId.match(/^owner_promo_target__(.+?)__(.+)$/);
if (targetButton) {
  const session = loadSession(targetButton[1]);
  const draft = session ? (typeof session.parsed_payload_json === 'string' ? JSON.parse(session.parsed_payload_json || '{}') : session.parsed_payload_json || {}) : null;
  const options = session ? (typeof session.preview_rows_json === 'string' ? JSON.parse(session.preview_rows_json || '[]') : session.preview_rows_json || []) : [];
  const chosen = options.find((row) => String(row.target_sku || '') === String(targetButton[2] || ''));
  if (!draft || !chosen) return [{ json: { ...base, action: 'clarify', clarify_message: 'I could not find that pending discount choice. Please start the discount again.' } }];
  const merged = { ...draft, ...chosen };
  if (!merged.valid_until) return [{ json: { ...base, action: 'save_draft_session', session_id: targetButton[1], session_stage: 'awaiting_expiry', draft_payload: merged, choice_rows: [] } }];
  if (!merged.priority_value) return [{ json: { ...base, action: 'save_draft_session', session_id: targetButton[1], session_stage: 'awaiting_priority', draft_payload: merged, choice_rows: [] } }];
  return [{ json: { ...base, action: 'preview_promo', session_id: targetButton[1], preview_rows: [buildPreviewDraft(merged)] } }];
}

const expiryButton = buttonId.match(/^owner_promo_expiry__(.+?)__(today|d7|d30)$/);
if (expiryButton) {
  const session = loadSession(expiryButton[1]);
  const draft = session ? (typeof session.parsed_payload_json === 'string' ? JSON.parse(session.parsed_payload_json || '{}') : session.parsed_payload_json || {}) : null;
  if (!draft) return [{ json: { ...base, action: 'clarify', clarify_message: 'I could not find that pending discount session. Please start again.' } }];
  const expiryMap = { today: 'today', d7: '7 days', d30: '30 days' };
  const validUntil = parseExpiry(expiryMap[expiryButton[2]] || '');
  const merged = { ...draft, valid_until: validUntil };
  if (!merged.priority_value) return [{ json: { ...base, action: 'save_draft_session', session_id: expiryButton[1], session_stage: 'awaiting_priority', draft_payload: merged, choice_rows: [] } }];
  return [{ json: { ...base, action: 'preview_promo', session_id: expiryButton[1], preview_rows: [buildPreviewDraft(merged)] } }];
}

const priorityButton = buttonId.match(/^owner_promo_priority__(.+?)__(high|medium|low)$/);
if (priorityButton) {
  const session = loadSession(priorityButton[1]);
  const draft = session ? (typeof session.parsed_payload_json === 'string' ? JSON.parse(session.parsed_payload_json || '{}') : session.parsed_payload_json || {}) : null;
  if (!draft) return [{ json: { ...base, action: 'clarify', clarify_message: 'I could not find that pending discount session. Please start again.' } }];
  const priority = parsePriority(priorityButton[2]) || { label: 'Medium', value: 20 };
  const merged = { ...draft, priority_label: priority.label, priority_value: priority.value };
  return [{ json: { ...base, action: 'preview_promo', session_id: priorityButton[1], preview_rows: [buildPreviewDraft(merged)] } }];
}

if (/^(?:show|list|active)\s*(?:promo|promos|promotions|offers|discounts)?$/i.test(message) || /^(?:show|list)\s+(?:all\s+)?(?:offers|promos|promotions|discounts)$/i.test(message)) {
  return [{ json: { ...base, action: 'list' } }];
}

const deactivateMatch = message.match(/^(?:remove|delete|deactivate|stop)\s+([A-Za-z0-9_-]+)$/i);
if (deactivateMatch) {
  return [{ json: { ...base, action: 'deactivate', promo_code: deactivateMatch[1].toUpperCase() } }];
}

const ai = parseAiPayload(aiText);
const intent = String(ai.intent || '').trim();
let promoType = String(ai.promo_type || '').trim();
let discountValue = ai.discount_value === null || ai.discount_value === undefined || ai.discount_value === '' ? null : Number(ai.discount_value);
let minCartValue = ai.min_cart_value === null || ai.min_cart_value === undefined || ai.min_cart_value === '' ? null : Number(ai.min_cart_value);
let targetText = String(ai.target_text || '').trim();
let expiryText = String(ai.expiry_text || '').trim();
let priorityText = String(ai.priority_text || '').trim();

if (!promoType || promoType === 'unknown') {
  const thresholdPctMatch = message.match(/^(\d+(?:\.\d+)?)%\s+off\s+above\s+(\d+(?:\.\d+)?)$/i);
  const flatMatch = message.match(/^flat\s+(\d+(?:\.\d+)?)\s+(?:off|discount)(?:\s+above\s+(\d+(?:\.\d+)?))?$/i);
  const productMatch = message.match(/^(\d+(?:\.\d+)?)%\s+(?:off|of)\s+(.+)$/i) || message.match(/^(.+?)\s+(\d+(?:\.\d+)?)%\s+(?:off|of)$/i);
  if (thresholdPctMatch) {
    promoType = 'order_percentage_threshold';
    discountValue = Number(thresholdPctMatch[1]);
    minCartValue = Number(thresholdPctMatch[2]);
  } else if (flatMatch) {
    promoType = 'order_flat';
    discountValue = Number(flatMatch[1]);
    minCartValue = flatMatch[2] ? Number(flatMatch[2]) : 0;
  } else if (productMatch) {
    promoType = 'product_percentage';
    if (message.match(/^(\d+(?:\.\d+)?)%\s+(?:off|of)\s+(.+)$/i)) {
      discountValue = Number(productMatch[1]);
      targetText = String(productMatch[2] || '').trim();
    } else {
      targetText = String(productMatch[1] || '').trim();
      discountValue = Number(productMatch[2]);
    }
  }
}

if (!intent && !promoType && !/(discount|promo|offer|flat|off|above)/i.test(message)) {
  return [{ json: { ...base, action: 'prompt_discount' } }];
}

if ((!promoType || promoType === 'unknown') && /(discount|promo|offer|flat|off|above)/i.test(message) && /\d/.test(message)) {
  return [{ json: { ...base, action: 'clarify', clarify_message: 'I could not safely understand that discount yet. Try one of these formats:\\n- Onions 50% off\\n- flat 20 off\\n- 5% off above 300' } }];
}

if (intent === 'help') return [{ json: { ...base, action: 'prompt_discount' } }];
if (intent === 'list_promos') return [{ json: { ...base, action: 'list' } }];
if (intent === 'deactivate_promo' && ai.promo_code) return [{ json: { ...base, action: 'deactivate', promo_code: String(ai.promo_code).toUpperCase() } }];

const priority = parsePriority(priorityText);
const validUntil = parseExpiry(expiryText);
const draft = {
  promo_scope: '',
  discount_type: '',
  discount_value: Number(discountValue || 0),
  min_cart_value: Number(minCartValue || 0),
  target_text: targetText,
  target_sku: '',
  target_label: '',
  target_category: '',
  valid_until: validUntil,
  priority_label: priority ? priority.label : '',
  priority_value: priority ? priority.value : 0,
  promo_code: String(ai.promo_code || '').trim().toUpperCase(),
};

if (promoType === 'order_flat') {
  draft.promo_scope = 'order';
  draft.discount_type = 'flat';
  draft.target_label = draft.min_cart_value > 0 ? ('orders above Rs.' + draft.min_cart_value) : 'the order';
} else if (promoType === 'order_percentage_threshold') {
  draft.promo_scope = 'order';
  draft.discount_type = 'percentage';
  draft.target_label = 'orders above Rs.' + draft.min_cart_value;
} else if (promoType === 'order_percentage') {
  draft.promo_scope = 'order';
  draft.discount_type = 'percentage';
  draft.target_label = 'the order';
} else if (promoType === 'product_percentage') {
  draft.promo_scope = 'product';
  draft.discount_type = 'percentage';
  const resolution = resolveItem(targetText);
  if (resolution.status === 'not_found') {
    return [{ json: { ...base, action: 'clarify', clarify_message: 'I could not find ' + targetText + '. Create the item first or use a more specific name.' } }];
  }
  if (resolution.status === 'ambiguous') {
    return [{ json: { ...base, action: 'save_draft_session', session_stage: 'awaiting_target', draft_payload: draft, choice_rows: resolution.options } }];
  }
  draft.target_sku = String(resolution.row.sku || '');
  draft.target_label = resolution.row.item_name;
  draft.target_category = resolution.row.category || '';
} else {
  return [{ json: { ...base, action: 'prompt_discount' } }];
}

if (!draft.valid_until) return [{ json: { ...base, action: 'save_draft_session', session_stage: 'awaiting_expiry', draft_payload: draft, choice_rows: [] } }];
if (!draft.priority_value) return [{ json: { ...base, action: 'save_draft_session', session_stage: 'awaiting_priority', draft_payload: draft, choice_rows: [] } }];
return [{ json: { ...base, action: 'preview_promo', preview_rows: [buildPreviewDraft(draft)] } }];

const d = $('Parse Promo Request').first().json;
const lang = String(d.user_language || 'en');
const OWNER_BUTTON_LABELS = {
