  hi: { accept: '✅ स्वीकार', reject: '❌ अस्वीकार', mark_ready: '📦 तैयार', mark_delivered: '🚚 डिलीवर', view_orders: '📋 ऑर्डर', add_item: '➕ जोड़ें', edit_item: '✏️ संपादित', remove_item: '🗑 हटाएं', view_inventory: '📦 इन्वेंटरी', add_promo: '🏷 प्रोमो जोड़ें', view_promos: '🏷 प्रोमो', language: '🌐 भाषा', mark_dispatched: '🚚 भेजा' },
