let bodyText = '';
if (!rows.length) {
  bodyText = 'No active promotions right now.';
} else {
  const lines = [];
  for (const row of rows) {
    const value = Number(row.discount_value || 0);
    const discountLabel = row.discount_type === 'percentage' ? value + '% off' : 'Rs.' + value + ' off';
    const targetCount = Number(row.target_count || 0);
    const labels = String(row.target_labels || '').split(' | ').filter(Boolean);
    let scopeLabel = 'on the order';
    if (row.promo_scope === 'product') {
      if (targetCount > 1) {
        const preview = labels.slice(0, 3).join(', ');
        scopeLabel = 'on ' + targetCount + ' items' + (preview ? ' (' + preview + (labels.length > 3 ? ', ...' : '') + ')' : '');
      } else {
        scopeLabel = 'on ' + (labels[0] || 'one item');
      }
    } else if (Number(row.min_cart_value || 0) > 0) {
      scopeLabel = 'on orders above Rs.' + Number(row.min_cart_value || 0);
    } else if (row.promo_scope === 'category') {
      scopeLabel = 'on ' + (row.target_category || 'that category');
    }
    lines.push('- ' + (row.promo_group_code || row.promo_code) + ': ' + discountLabel + ' ' + scopeLabel);
  }
  bodyText = 'Active promotions:\n' + lines.join('\n');
}
return [{ json: { chat_id: d.chat_id, message_type: 'text', body_text: bodyText, test_mode: d.test_mode === true } }];

const d = $('Parse Promo Request').first().json;
const schema = $('Inspect Promo Schema').first().json || {};
const esc = (value) => String(value === undefined || value === null ? '' : value).replace(/'/g, "''");
const b = (value) => value === true || value === 'true' || value === 't' || value === 1 || value === '1';
const hasStoreId = b(schema.has_store_id);
const hasIsActive = b(schema.has_is_active);
const hasUpdatedAt = b(schema.has_updated_at);
const hasCreatedAt = b(schema.has_created_at);
const hasPriority = b(schema.has_priority);
const hasDescription = b(schema.has_description);
const hasDiscountType = b(schema.has_discount_type);
const hasDiscountValue = b(schema.has_discount_value);
const hasMinCartValue = b(schema.has_min_cart_value);
const hasPromoScope = b(schema.has_promo_scope);
const hasTargetSku = b(schema.has_target_sku);
const hasTargetCategory = b(schema.has_target_category);
const hasValidUntil = b(schema.has_valid_until);
const storeId = Number(d.store_id || 0);
const resolvedStoreIdSql = hasStoreId
  ? (storeId > 0
      ? String(storeId)
      : "(SELECT store_id FROM public.stores WHERE owner_whatsapp_number = '" + esc(d.chat_id) + "' ORDER BY COALESCE(onboarding_step, 0) DESC, COALESCE(store_id, 0) DESC, created_at DESC NULLS LAST LIMIT 1)")
  : 'NULL';

const tableSql = [
  'CREATE TABLE IF NOT EXISTS public.owner_operation_sessions (',
  '  session_id TEXT PRIMARY KEY,',
  '  store_id BIGINT,',
  '  chat_id TEXT NOT NULL,',
  '  operation_type TEXT NOT NULL,',
  '  source_type TEXT NOT NULL,',
  "  parsed_payload_json JSONB DEFAULT '{}'::jsonb,",
  "  cleanup_summary_json JSONB DEFAULT '{}'::jsonb,",
  "  preview_rows_json JSONB DEFAULT '[]'::jsonb,",
  '  status TEXT NOT NULL,',
  '  created_at TIMESTAMPTZ DEFAULT NOW(),',
  '  updated_at TIMESTAMPTZ DEFAULT NOW()',
  ');',
].join('\n');

function jsonLiteral(value) {
  return "'" + esc(JSON.stringify(value)) + "'::jsonb";
}

const activeSessionWhere = "chat_id = '" + esc(d.chat_id) + "' AND status NOT IN ('cancelled', 'applied', 'completed', 'completed_with_issues', 'failed')";

if (d.action === 'start_prompt_session') {
  const sessionId = 'promo_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
  const summary = { stage: 'awaiting_details' };
  const sql = [
    tableSql,
    "UPDATE public.owner_operation_sessions SET status = 'cancelled', updated_at = NOW() WHERE " + activeSessionWhere + ";",
    'WITH upserted AS (',
    '  INSERT INTO public.owner_operation_sessions (session_id, store_id, chat_id, operation_type, source_type, parsed_payload_json, cleanup_summary_json, preview_rows_json, status, created_at, updated_at)',
    "  VALUES ('" + esc(sessionId) + "', " + resolvedStoreIdSql + ", '" + esc(d.chat_id) + "', 'promo_draft', '" + esc(d.source_type || 'text') + "', '{}'::jsonb, " + jsonLiteral(summary) + ", '[]'::jsonb, 'awaiting_details', NOW(), NOW())",
    '  RETURNING session_id',
    ')',
    "SELECT 'prompt_ready' AS result, session_id, " + jsonLiteral(summary) + " AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches FROM upserted;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
}

if (d.action === 'save_draft_session') {
  const sessionId = d.session_id || ('promo_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8));
  const stage = d.session_stage || 'awaiting_expiry';
  const sql = [
    tableSql,
    "UPDATE public.owner_operation_sessions SET status = 'cancelled', updated_at = NOW() WHERE " + activeSessionWhere + " AND session_id <> '" + esc(sessionId) + "';",
    'WITH upserted AS (',
    '  INSERT INTO public.owner_operation_sessions (session_id, store_id, chat_id, operation_type, source_type, parsed_payload_json, cleanup_summary_json, preview_rows_json, status, created_at, updated_at)',
    "  VALUES ('" + esc(sessionId) + "', " + resolvedStoreIdSql + ", '" + esc(d.chat_id) + "', 'promo_draft', '" + esc(d.source_type || 'text') + "', " + jsonLiteral(d.draft_payload || {}) + ", " + jsonLiteral({ stage }) + ", " + jsonLiteral(d.choice_rows || []) + ", '" + esc(stage) + "', NOW(), NOW())",
    '  ON CONFLICT (session_id) DO UPDATE SET',
    "    parsed_payload_json = EXCLUDED.parsed_payload_json, cleanup_summary_json = EXCLUDED.cleanup_summary_json, preview_rows_json = EXCLUDED.preview_rows_json, status = EXCLUDED.status, updated_at = NOW()",
    '  RETURNING session_id, status, cleanup_summary_json AS summary, preview_rows_json AS preview_rows',
    ')',
    "SELECT status AS result, session_id, summary, preview_rows, NULL::json AS promo, '[]'::json AS matches FROM upserted;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
}

if (d.action === 'preview_promo') {
  const previewRow = (d.preview_rows || [])[0] || {};
  const sessionId = d.session_id || ('promo_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8));
  const summary = { existing_active_code: previewRow.existing_active_code || '' };
  const sql = [
    tableSql,
    "UPDATE public.owner_operation_sessions SET status = 'cancelled', updated_at = NOW() WHERE " + activeSessionWhere + " AND session_id <> '" + esc(sessionId) + "';",
    'WITH upserted AS (',
    '  INSERT INTO public.owner_operation_sessions (session_id, store_id, chat_id, operation_type, source_type, parsed_payload_json, cleanup_summary_json, preview_rows_json, status, created_at, updated_at)',
    "  VALUES ('" + esc(sessionId) + "', " + resolvedStoreIdSql + ", '" + esc(d.chat_id) + "', 'promo_preview', '" + esc(d.source_type || 'text') + "', " + jsonLiteral(previewRow) + ", " + jsonLiteral(summary) + ", " + jsonLiteral(d.preview_rows || []) + ", 'pending_preview', NOW(), NOW())",
    '  ON CONFLICT (session_id) DO UPDATE SET',
    "    parsed_payload_json = EXCLUDED.parsed_payload_json, cleanup_summary_json = EXCLUDED.cleanup_summary_json, preview_rows_json = EXCLUDED.preview_rows_json, status = EXCLUDED.status, updated_at = NOW()",
    '  RETURNING session_id, cleanup_summary_json AS summary, preview_rows_json AS preview_rows',
    ')',
    "SELECT 'preview_created' AS result, session_id, summary, preview_rows, NULL::json AS promo, '[]'::json AS matches FROM upserted;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
}

if (d.action === 'cancel_session') {
  const sql = [
    tableSql,
    "WITH updated AS (UPDATE public.owner_operation_sessions SET status = 'cancelled', updated_at = NOW() WHERE " + activeSessionWhere + " RETURNING session_id)",
    "SELECT CASE WHEN EXISTS (SELECT 1 FROM updated) THEN 'cancelled' ELSE 'session_missing' END AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
}

if (d.action === 'confirm_session') {
  if (!hasDiscountType || !hasDiscountValue) {
    return [{ json: { ...d, sql: "SELECT 'schema_missing_core' AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches;" } }];
  }
  if (!hasTargetSku && String(d.promo_scope || '') === 'product') {
    return [{ json: { ...d, sql: "SELECT 'schema_missing_target_sku' AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches;" } }];
  }
  const insertColumns = ['promo_code', 'discount_type', 'discount_value'];
  const selectCols = ['r.promo_code', 'r.discount_type', 'r.discount_value'];
  const updateParts = ['discount_type = EXCLUDED.discount_type', 'discount_value = EXCLUDED.discount_value'];
  if (hasPromoScope) { insertColumns.push('promo_scope'); selectCols.push('r.promo_scope'); updateParts.push('promo_scope = EXCLUDED.promo_scope'); }
  if (hasMinCartValue) { insertColumns.push('min_cart_value'); selectCols.push('COALESCE(r.min_cart_value, 0)'); updateParts.push('min_cart_value = EXCLUDED.min_cart_value'); }
  if (hasDescription) { insertColumns.push('description'); selectCols.push('r.description'); updateParts.push('description = EXCLUDED.description'); }
  if (hasStoreId) { insertColumns.push('store_id'); selectCols.push(resolvedStoreIdSql); updateParts.push('store_id = EXCLUDED.store_id'); }
  if (hasTargetSku) { insertColumns.push('target_sku'); selectCols.push("NULLIF(r.target_sku, '')"); updateParts.push('target_sku = EXCLUDED.target_sku'); }
  if (hasTargetCategory) { insertColumns.push('target_category'); selectCols.push("NULLIF(r.target_category, '')"); updateParts.push('target_category = EXCLUDED.target_category'); }
  if (hasPriority) { insertColumns.push('priority'); selectCols.push('COALESCE(r.priority_value, 20)'); updateParts.push('priority = EXCLUDED.priority'); }
  if (hasValidUntil) { insertColumns.push('valid_until'); selectCols.push("CASE WHEN NULLIF(r.valid_until, '') IS NULL THEN NULL ELSE NULLIF(r.valid_until, '')::timestamptz END"); updateParts.push('valid_until = EXCLUDED.valid_until'); }
  if (hasIsActive) { insertColumns.push('is_active'); selectCols.push('true'); updateParts.push('is_active = true'); }
  if (hasCreatedAt) { insertColumns.push('created_at'); selectCols.push('NOW()'); }
  if (hasUpdatedAt) { insertColumns.push('updated_at'); selectCols.push('NOW()'); updateParts.push('updated_at = NOW()'); }
  const sql = [
    tableSql,
    'WITH session_row AS (',
    "  SELECT * FROM public.owner_operation_sessions WHERE session_id = '" + esc(d.session_id) + "' AND chat_id = '" + esc(d.chat_id) + "' LIMIT 1",
    '), session_status AS (SELECT COALESCE((SELECT status FROM session_row), \'missing\') AS status), safe_rows AS (',
    "  SELECT * FROM jsonb_to_recordset(COALESCE((SELECT preview_rows_json FROM session_row), '[]'::jsonb)) AS r(promo_code text, promo_scope text, discount_type text, discount_value numeric, min_cart_value numeric, target_sku text, target_label text, target_category text, description text, valid_until text, priority_value numeric, priority_label text)",
    '), upserted AS (',
    '  INSERT INTO public.promotions (' + insertColumns.join(', ') + ')',
    '  SELECT ' + selectCols.join(', '),
    '  FROM safe_rows r, session_status st',
    "  WHERE st.status = 'pending_preview'",
    '  ON CONFLICT (promo_code) DO UPDATE SET ' + updateParts.join(', '),
    '  RETURNING promo_code',
    '), session_done AS (',
    "  UPDATE public.owner_operation_sessions SET status = CASE WHEN (SELECT status FROM session_status) = 'pending_preview' THEN 'applied' ELSE status END, updated_at = NOW() WHERE session_id = '" + esc(d.session_id) + "' RETURNING status",
    ')',
    "SELECT CASE WHEN (SELECT status FROM session_status) = 'pending_preview' THEN 'applied' WHEN (SELECT status FROM session_status) = 'applied' THEN 'already_applied' WHEN (SELECT status FROM session_status) = 'cancelled' THEN 'cancelled' ELSE 'session_missing' END AS result, json_build_object('promo_count', (SELECT COUNT(*) FROM upserted)) AS summary, (SELECT row_to_json(u) FROM upserted u LIMIT 1) AS promo, '[]'::jsonb AS preview_rows, '[]'::json AS matches;",
  ].join('\n');
  return [{ json: { ...d, sql } }];
}

if (d.action === 'deactivate') {
  const setParts = [];
  if (hasIsActive) setParts.push('is_active = false');
  if (hasUpdatedAt) setParts.push('updated_at = NOW()');
  const sql = setParts.length
    ? "WITH updated AS (UPDATE public.promotions SET " + setParts.join(', ') + " WHERE promo_code = '" + esc(d.promo_code) + "'" + (hasStoreId ? " AND store_id = " + resolvedStoreIdSql : "") + " RETURNING promo_code) SELECT CASE WHEN EXISTS (SELECT 1 FROM updated) THEN 'deactivated' ELSE 'not_found' END AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, (SELECT row_to_json(u) FROM updated u LIMIT 1) AS promo, '[]'::json AS matches;"
    : "SELECT 'schema_missing_core' AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches;";
  return [{ json: { ...d, sql } }];
}

return [{ json: { ...d, sql: "SELECT 'session_missing' AS result, '{}'::jsonb AS summary, '[]'::jsonb AS preview_rows, NULL::json AS promo, '[]'::json AS matches;" } }];

const d = $('Parse Promo Request').first().json;
const row = $input.first().json || {};
const parseMaybeJson = (value, fallback) => {
  if (value === undefined || value === null || value === '') return fallback;
  if (Array.isArray(value) || typeof value === 'object') return value;
  try { return JSON.parse(value); } catch { return fallback; }
};
const summary = parseMaybeJson(row.summary, {});
const previewRows = parseMaybeJson(row.preview_rows, d.preview_rows || []);
const promo = parseMaybeJson(row.promo, null);
const makeText = (body) => ({ chat_id: d.chat_id, message_type: 'text', body_text: body, test_mode: d.test_mode === true });
const makeButtons = (body, buttons) => ({ chat_id: d.chat_id, message_type: 'button', body_text: body, buttons, test_mode: d.test_mode === true });

if (row.result === 'schema_missing_core') return [{ json: makeText('Promotion storage is missing required columns.') }];
if (row.result === 'schema_missing_target_sku') return [{ json: makeText('This database is missing target_sku, so item-specific promos cannot be created safely yet.') }];

if (row.result === 'awaiting_target') {
  const sessionId = String(row.session_id || '');
  const options = previewRows.slice(0, 3);
  const lines = options.map((item) => '- ' + item.target_label).join('\n');
  return [{ json: makeButtons(
    'I found multiple catalog items for this discount.\n' + lines + '\n\nChoose the exact item before I continue.',
    options.map((item) => ({ id: 'owner_promo_target__' + sessionId + '__' + item.target_sku, title: item.target_label.slice(0, 20) })),
  ) }];
}

if (row.result === 'awaiting_expiry') {
  const sessionId = String(row.session_id || '');
  return [{ json: makeButtons(
    'Choose an expiry for this discount.',
    [
      { id: 'owner_promo_expiry__' + sessionId + '__today', title: 'Today' },
      { id: 'owner_promo_expiry__' + sessionId + '__d7', title: '7 days' },
      { id: 'owner_promo_expiry__' + sessionId + '__d30', title: '30 days' },
    ],
  ) }];
}

if (row.result === 'awaiting_priority') {
  const sessionId = String(row.session_id || '');
  return [{ json: makeButtons(
    'Choose a priority for this discount.',
    [
      { id: 'owner_promo_priority__' + sessionId + '__high', title: 'High' },
      { id: 'owner_promo_priority__' + sessionId + '__medium', title: 'Medium' },
      { id: 'owner_promo_priority__' + sessionId + '__low', title: 'Low' },
    ],
  ) }];
}

if (row.result === 'preview_created') {
  const sessionId = String(row.session_id || '');
  const preview = previewRows[0] || {};
  const discountLabel = preview.discount_type === 'percentage'
    ? Number(preview.discount_value || 0) + '% off'
    : 'Rs.' + Number(preview.discount_value || 0) + ' off';
  const scopeLabel = preview.promo_scope === 'product'
    ? 'on ' + preview.target_label
    : Number(preview.min_cart_value || 0) > 0
      ? 'on orders above Rs.' + Number(preview.min_cart_value || 0)
      : 'on the order';
  const extra = summary.existing_active_code ? '\nExisting active promo: ' + summary.existing_active_code : '';
  const expiry = preview.valid_until ? new Date(preview.valid_until).toLocaleDateString('en-IN') : 'not set';
  const priority = preview.priority_label || 'Medium';
  return [{ json: makeButtons(
    'Discount preview:\n\nCode: ' + preview.promo_code + '\nOffer: ' + discountLabel + ' ' + scopeLabel + '\nExpiry: ' + expiry + '\nPriority: ' + priority + extra + '\n\nConfirm to publish this discount.',
    [
      { id: 'owner_promo_confirm__' + sessionId, title: 'Confirm discount' },
      { id: 'owner_promo_cancel__' + sessionId, title: 'Cancel' },
    ],
  ) }];
}

if (row.result === 'prompt_ready') {
  return [{ json: makeButtons(
    'Create discounts with messages like:\n- 50% off Eggs 10\n- Onions 50% off\n- flat 20 off\n- 5% off above 300\n\nI will stay in discount mode until you finish or cancel.',
    [
      { id: 'owner_catalog_import', title: 'Upload stock sheet' },
      { id: 'owner_catalog_update', title: 'Update stock/price' },
      { id: 'owner_catalog_home', title: 'Menu' },
    ],
  ) }];
}

if (row.result === 'applied') {
  return [{ json: makeButtons(
    'Discount saved. Promo ' + ((promo && promo.promo_code) || 'code') + ' is now active.',
    [
      { id: 'owner_promo_create_another', title: 'Create another' },
      { id: 'owner_promo_show_active', title: 'Show active' },
      { id: 'owner_promo_back_catalog', title: 'Back to catalog' },
    ],
  ) }];
}

if (row.result === 'already_applied') {
  return [{ json: makeButtons(
    'That discount preview was already applied earlier.',
    [
      { id: 'owner_promo_create_another', title: 'Create another' },
      { id: 'owner_promo_show_active', title: 'Show active' },
      { id: 'owner_promo_back_catalog', title: 'Back to catalog' },
    ],
  ) }];
}
if (row.result === 'cancelled') {
  return [{ json: makeButtons(
    'Cancelled. No promotion changes were applied.',
    [
      { id: 'owner_promo_create_another', title: 'Create another' },
      { id: 'owner_promo_show_active', title: 'Show active' },
      { id: 'owner_promo_back_catalog', title: 'Back to catalog' },
    ],
  ) }];
}
if (row.result === 'deactivated') return [{ json: makeText('Promo ' + ((promo && promo.promo_code) || d.promo_code) + ' deactivated.') }];
if (row.result === 'not_found' || row.result === 'session_missing') {
  return [{ json: makeButtons(
    'I could not find that pending discount action. Please start the discount again.',
    [
      { id: 'owner_promo_create_another', title: 'Create another' },
      { id: 'owner_promo_show_active', title: 'Show active' },
      { id: 'owner_promo_back_catalog', title: 'Back to catalog' },
    ],
  ) }];
}
return [{ json: makeText('I could not save that discount safely. Please try again with a clearer message.') }];
